import numpy as np

# e^(-x^2) has NO algebraic anti-derivative
# We must use numerical integration
def f(x):
    return np.exp(-x**2)

def trap_integral(f, a, b, n=10000):
    x = np.linspace(a, b, n+1)
    y = f(x)
    return np.trapz(y, x)

# Approximate ∫₋₃³ e^(-x²) dx
# Exact (full integral): sqrt(pi) ≈ 1.7725
result = trap_integral(f, -3, 3)
print(f"∫₋₃³ e^(-x²) dx ≈ {result:.6f}")
print(f"sqrt(pi)         = {np.sqrt(np.pi):.6f}")
print(f"Error            = {abs(result - np.sqrt(np.pi)):.8f}")

# Convergence demo: sin(x²)
def g(x):
    return np.sin(x**2)

print(f"\n∫₀⁴ sin(x²) dx ≈ {trap_integral(g, 0, 4):.6f}")
print("(No algebraic anti-derivative exists)")
